nctuation\">}</span><span class=\"token punctuation\">)</span><span class=\"token punctuation\">;</span>\n  fs<span class=\"token punctuation\">.</span><span class=\"token function\">writeFileSync</span><span class=\"token punctuation\">(</span><span class=\"token template-string\"><span class=\"token template-punctuation string\">`</span><span class=\"token interpolation\"><span class=\"token interpolation-punctuation punctuation\">${</span><span class=\"token constant\">API_PATH</span><span class=\"token interpolation-punctuation punctuation\">}</span></span><span class=\"token string\">/</span><span class=\"token interpolation\"><span class=\"token interpolation-punctuation punctuation\">${</span>fileName<span class=\"token interpolation-punctuation punctuation\">}</span></span><span class=\"token string\">.ts</span><span class=\"token template-punctuation string\">`</span></span><span class=\"token punctuation\">,</span> tplIndex<span class=\"token punctuation\">)</span><span class=\"token punctuation\">;</span>\n  console<span class=\"token punctuation\">.</span><span class=\"token function\">log</span><span class=\"token punctuation\">(</span>\n    chalk<span class=\"token punctuation\">.</span><span class=\"token function\">blue</span><span class=\"token punctuation\">(</span>\n      <span class=\"token template-string\"><span class=\"token template-punctuation string\">`</span><span class=\"token interpolation\"><span class=\"token interpolation-punctuation punctuation\">${</span>fileName<span class=\"token interpolation-punctuation punctuation\">}</span></span><span class=\"token string\">.ts</span><span class=\"token template-punctuation string\">`</span></span> <span class=\"token operator\">+</span>\n        chalk<span class=\"token punctuation\">.</span><span class=\"token function\">green</span><span class=\"token punctuation\">(</span><span class=\"token string\">\" ------------ \"</span><span class=\"token punctuation\">)</span> <span class=\"token operator\">+</span>\n        chalk<span class=\"token punctuation\">.</span><span class=\"token function\">black</span><span class=\"token punctuation\">(</span><span class=\"token string\">\"[\"</span> <span class=\"token operator\">+</span> apiDataLen <span class=\"token operator\">+</span> <span class=\"token string\">\"]\"</span><span class=\"token punctuation\">)</span> <span class=\"token operator\">+</span>\n        chalk<span class=\"token punctuation\">.</span><span class=\"token function\">green</span><span class=\"token punctuation\">(</span><span class=\"token string\">\"个接口写入完成\"</span><span class=\"token punctuation\">)</span>\n    <span class=\"token punctuation\">)</span>\n  <span class=\"token punctuation\">)</span><span class=\"token punctuation\">;</span>\n  <span class=\"token keyword\">return</span> moduleList<span class=\"token punctuation\">;</span>\n<span class=\"token punctuation\">}</span><span class=\"token punctuation\">;</span>\n\n<span class=\"token keyword\">const</span> <span class=\"token function-variable function\">gen</span> <span class=\"token operator\">=</span> <span class=\"token keyword\">async</span> <span class=\"token punctuation\">(</span><span class=\"token punctuation\">)</span> <span class=\"token operator\">=&gt;</span> <span class=\"token punctuation\">{</span>\n  <span class=\"token function\">rmDir</span><span class=\"token punctuation\">(</span><span class=\"token constant\">API_PATH</span><span class=\"token punctuation\">)</span><span class=\"token punctuation\">;</span>\n  <span class=\"token function\">isExist</span><span class=\"token punctuation\">(</span><span class=\"token punctuation\">)</span><span class=\"token punctuation\">;</span>\n  <span class=\"token keyword\">try</span> <span class=\"token punctuation\">{</span>\n    <span class=\"token keyword\">let</span> parsed<span class=\"token punctuation\">;</span>\n    <span class=\"token keyword\">if</span> <span class=\"token punctuation\">(</span>demo<span class=\"token punctuation\">)</span> <span class=\"token punctuation\">{</span>\n      parsed <span class=\"token operator\">=</span> demoData<span class=\"token punctuation\">;</span>\n    <span class=\"token punctuation\">}</span> <span class=\"token keyword\">else</span> <span class=\"token punctuation\">{</span>\n      <span class=\"token comment\">// 解析url 获得</span>\n      parsed <span class=\"token operator\">=</span> <span class=\"token keyword\">await</span> parse<span class=\"token punctuation\">.</span><span class=\"token function\">parse</span><span class=\"token punctuation\">(</span>swaggerUrl<span class=\"token punctuation\">)</span><span class=\"token punctuation\">;</span>\n    <span class=\"token punctuation\">}</span>\n\n    <span class=\"token keyword\">const</span> paths <span class=\"token operator\">=</span> parsed<span class=\"token punctuation\">.</span>paths<span class=\"token punctuation\">;</span>\n    <span class=\"token keyword\">const</span> pathsKeys <span class=\"token operator\">=</span> Object<span class=\"token punctuation\">.</span><span class=\"token function\">keys</span><span class=\"token punctuation\">(</span>paths<span class=\"token punctuation\">)</span><span class=\"token punctuation\">;</span>\n    <span class=\"token keyword\">const</span> pathsKeysLen <span class=\"token operator\">=</span> pathsKeys<span class=\"token punctuation\">.</span>length<span class=\"token punctuation\">;</span>\n    console<span class=\"token punctuation\">.</span><span class=\"token function\">log</span><span class=\"token punctuation\">(</span>\n      chalk<span class=\"token punctuation\">.</span><span class=\"token function\">blue</span><span class=\"token punctuation\">(</span><span class=\"token string\">\"开始解析，总共接口数量：\"</span><span class=\"token punctuation\">)</span> <span class=\"token operator\">+</span> chalk<span class=\"token punctuation\">.</span><span class=\"token function\">yellow</span><span class=\"token punctuation\">(</span>pathsKeysLen<span class=\"token punctuation\">)</span>\n    <span class=\"token punctuation\">)</span><span class=\"token punctuation\">;</span>\n    console<span class=\"token punctuation\">.</span><span class=\"token function\">log</span><span class=\"token punctuation\">(</span>\n      chalk<span class=\"token punctuation\">.</span><span class=\"token function\">red</span><span class=\"token punctuation\">(</span>\n        <span class=\"token string\">\"---------------------------------------------------------------\"</span>\n      <span class=\"token punctuation\">)</span>\n    <span class=\"token punctuation\">)</span><span class=\"token punctuation\">;</span>\n\n    <span class=\"token keyword\">const</span> modulesMap <span class=\"token operator\">=</span> <span class=\"token keyword\">new</span> <span class=\"token class-name\">Map</span><span class=\"token punctuation\">(</span><span class=\"token punctuation\">)</span><span class=\"token punctuation\">;</span>\n    <span class=\"token keyword\">for</span> <span class=\"token punctuation\">(</span><span class=\"token keyword\">let</span> i <span class=\"token operator\">=</span> <span class=\"token number\">0</span><span class=\"token punctuation\">;</span> i <span class=\"token operator\">&lt;</span> pathsKeysLen<span class=\"token punctuation\">;</span> i<span class=\"token operator\">++</span><span class=\"token punctuation\">)</span> <span class=\"token punctuation\">{</span>\n      <span class=\"token keyword\">const</span> item <span class=\"token operator\">=</span> pathsKeys<span class=\"token punctuation\">[</span>i<span class=\"token punctuation\">]</span><span class=\"token punctuation\">;</span>\n      <span class=\"token keyword\">const</span> itemAry <span class=\"token operator\">=</span> item<span class=\"token punctuation\">.</span><span class=\"token function\">split</span><span class=\"token punctuation\">(</span><span class=\"token string\">\"/\"</span><span class=\"token punctuation\">)</span><span class=\"token punctuation\">;</span>\n      <span class=\"token keyword\">const</span> pathsItem <span class=\"token operator\">=</span> paths<span class=\"token punctuation\">[</span>item<span class=\"token punctuation\">]</span><span class=\"token punctuation\">;</span>\n      <span class=\"token keyword\">let</span> fileName <span class=\"token operator\">=</span> itemAry<span class=\"token punctuation\">[</span>dirIdx <span class=\"token operator\">||</span> <span class=\"token number\">2</span><span class=\"token punctuation\">]</span><span class=\"token punctuation\">;</span>\n      <span class=\"token keyword\">if</span> <span class=\"token punctuation\">(</span><span class=\"token operator\">!</span>fileName<span class=\"token punctuation\">)</span> <span class=\"token keyword\">continue</span><span class=\"token punctuation\">;</span>\n      fileName <span class=\"token operator\">=</span> fileName<span class=\"token punctuation\">.</span><span class=\"token function\">toLowerCase</span><span class=\"token punctuation\">(</span><span class=\"token punctuation\">)</span><span class=\"token punctuation\">;</span>\n      pathsItem<span class=\"token punctuation\">.</span>allPath <span class=\"token operator\">=</span> item<span class=\"token punctuation\">;</span>\n      <span class=\"token keyword\">if</span> <span class=\"token punctuation\">(</span>modulesMap<span class=\"token punctuation\">.</span><span class=\"token function\">has</span><span class=\"token punctuation\">(</span>fileName<span class=\"token punctuation\">)</span><span class=\"token punctuation\">)</span> <span class=\"token punctuation\">{</span>\n        <span class=\"token comment\">// 继续添加到当前 fileName 文件内</span>\n        <span class=\"token keyword\">const</span> fileNameAry <span class=\"token operator\">=</span> modulesMap<span class=\"token punctuation\">.</span><span class=\"token function\">get</span><span class=\"token punctuation\">(</span>fileName<span class=\"token punctuation\">)</span><span class=\"token punctuation\">;</span>\n        fileNameAry<span class=\"token punctuation\">.</span><span class=\"token function\">push</span><span class=\"token punctuation\">(</span>pathsItem<span class=\"token punctuation\">)</span><span class=\"token punctuation\">;</span>\n        modulesMap<span class=\"token punctuation\">.</span><span class=\"token function\">set</span><span class=\"token punctuation\">(</span>fileName<span class=\"token punctuation\">,</span> fileNameAry<span class=\"token punctuation\">)</span><span class=\"token punctuation\">;</span>\n      <span class=\"token punctuation\">}</span> <span class=\"token keyword\">else</span> <span class=\"token punctuation\">{</span>\n        modulesMap<span class=\"token punctuation\">.</span><span class=\"token function\">set</span><span class=\"token punctuation\">(</span>fileName<span class=\"token punctuation\">,</span> <span class=\"token punctuation\">[</span>pathsItem<span class=\"token punctuation\">]</span><span class=\"token punctuation\">)</span><span class=\"token punctuation\">;</span>\n      <span class=\"token punctuation\">}</span>\n    <span class=\"token punctuation\">}</span>\n    <span class=\"token comment\">// 获取模块，并写入文件</span>\n    <span class=\"token function\">getModules</span><span class=\"token punctuation\">(</span>modulesMap<span class=\"token punctuation\">)</span><span class=\"token punctuation\">;</span>\n  <span class=\"token punctuation\">}</span> <span class=\"token keyword\">catch</span> <span class=\"token punctuation\">(</span>e<span class=\"token punctuation\">)</span> <span class=\"token punctuation\">{</span>\n    console<span class=\"token punctuation\">.</span><span class=\"token function\">log</span><span class=\"token punctuation\">(</span>e<span class=\"token punctuation\">)</span><span class=\"token punctuation\">;</span>\n  <span class=\"token punctuation\">}</span>\n<span class=\"token punctuation\">}</span><span class=\"token punctuation\">;</span>\n\nmodule<span class=\"token punctuation\">.</span>exports <span class=\"token operator\">=</span> <span class=\"token punctuation\">{</span>\n  gen<span class=\"token punctuation\">,</span>\n<span class=\"token punctuation\">}</span><span class=\"token punctuation\">;</span>\n\n</code></pre>\n\n    <button class=\"v-md-copy-code-btn\" type=\"button\">\n      <i>\n        <svg viewbox=\"64 64 896 896\" focusable=\"false\" data-icon=\"copy\" width=\"1em\" height=\"1em\" fill=\"currentColor\" aria-hidden=\"true\">\n          <path d=\"M832 64H296c-4.4 0-8 3.6-8 8v56c0 4.4 3.6 8 8 8h496v688c0 4.4 3.6 8 8 8h56c4.4 0 8-3.6 8-8V96c0-17.7-14.3-32-32-32zM704 192H192c-17.7 0-32 14.3-32 32v530.7c0 8.5 3.4 16.6 9.4 22.6l173.3 173.3c2.2 2.2 4.7 4 7.4 5.5v1.9h4.2c3.5 1.3 7.2 2 11 2H704c17.7 0 32-14.3 32-32V224c0-17.7-14.3-32-32-32zM350 856.2L263.9 770H350v86.2zM664 888H414V746c0-22.1-17.9-40-40-40H232V264h432v624z\"></path>\n        </svg>\n      </i>\n    </button></div></div><h2 data-v-md-heading=\"其他\" data-v-md-line=\"272\">其他</h2>\n<p data-v-md-line=\"273\">初次提交，在本公司项目中，使用是完全支持了，但是不可避免，可能存在问题，如有发现，欢迎提出，感谢！（后期有时间的话，打算搞成vscode插件）</p>\n",
    "text": "## 前言\n当前公司开发，后端通过swagger提供接口文档，开发某些模块时，一下子可能生成二三十个接口，前端使用的时候，需要一个一个copy到对应的api文件中，定义类型，引入接口等等，实在是麻烦！于是花了点时间，搞了下自动导出\n[github项目地址，欢迎提出问题，求个star😁](https://github.com/yj-liuzepeng/swagger-ts)\n## 思路\n\n 1. 通过 swagger-parser这个库，解析swagger文档地址，下面是swagger内容的一些说明，可参考\n \n\t\n\t```javascript\n\t// swagger文档\n\t// info：API的基本信息，包括标题、版本号、描述等。\n\t// host：API的主机名和端口号。\n\t// basePath：API的基本路径，通常是API的前缀。\n\t// schemes：API的协议，通常是http或https。\n\t// tags：API的标签，可以用于对API进行分类。\n\t// paths：API的路径和操作，包括HTTP方法、请求参数、响应内容等。\n\t\t// operationId: 用于指定操作的唯一标识符。\n\t\t// summary: 用于提供操作的简要说明。\n\t\t// description: 用于提供操作的详细说明。\n\t\t// tags: 用于对操作进行分类和组织。\n\t\t// parameters: 用于定义在操作中使用的参数，例如查询参数，请求体参数等。\n\t\t// requestBody: 用于定义操作的请求体。\n\t\t// responses: 用于定义操作的响应，包括响应代码和响应消息。\n\t\t// security: 用于指定操作所需的安全方案。\n\t\t// deprecated: 用于指定操作是否已被弃用。\n\t// parameters：API的公共参数，可以在多个API中共用。\n\t// responses：API的响应定义，包括响应码、响应内容等。\n\t// securityDefinitions：API的安全定义，包括认证方式、访问授权等。\n\t// security：API的安全配置，指定哪些API需要认证或授权。\n\t```\n 2. 获取解析中需要的信息，如接口类型、标题、描述、地址、参数等等\n 3. 遍历所有接口，根据配置的规则，生成内容，写入文件\n\n## 核心代码\n\n```javascript\nconst fs = require(\"fs\");\nconst path = require(\"path\");\nconst chalk = require(\"chalk\");\nconst beautify = require(\"js-beautify\").js_beautify;\nconst parse = require(\"swagger-parser\");\nconst { swaggerUrl, topConfig, apiConfig,dirIdx } = require(\"./config\");\nconst demoData = require(\"./demo.json\");\n\n// demo or swaggerUrl\nlet demo = process.env.rundemo;\nif (demo) {\n  console.log(\n    \"========================================测试demo========================================\"\n  );\n} else {\n  console.log(\n    \"========================================swaggerUrl========================================\"\n  );\n}\n\n// api接口方法存放目录\nconst API_PATH = path.resolve(__dirname, \"../api\");\n\n// 判断目录是否存在\nconst isExist = (lastPath = \"\") => {\n  const privatePath = `${lastPath ? API_PATH + \"/\" + lastPath : API_PATH}`;\n  const stat = fs.existsSync(privatePath);\n  if (!stat) {\n    fs.mkdirSync(privatePath);\n  }\n};\n\n// 清空文件夹\nconst rmDir = (dir) => {\n  if (fs.existsSync(dir)) {\n    const files = fs.readdirSync(dir);\n    if (files.length > 0) {\n      fs.rmdirSync(dir, { recursive: true });\n      fs.mkdirSync(dir);\n    }\n  }\n};\n\n// 接口名称处理 getColumnInfosUsingGET-->getColumnInfos  saveProjectUsingPOST-->saveProject\nconst moduleName = (operationId) => {\n  return operationId.replace(/Using(POST|GET)/g, \"\");\n};\n// 数据类型\nconst dataType = (key) => {\n  const type = {\n    string: \"string\",\n    integer: \"number\",\n    int: \"number\",\n    long: \"string\",\n    Array: \"array\",\n    file: \"Blob\",\n    boolean: \"boolean\",\n  };\n  return type[key] ? type[key] : \"any\";\n};\n\n// 获取模块\nconst getModules = (map) => {\n  let moduleList = [];\n  map.forEach((value, key) => {\n    const module = writeFileApi(key, value);\n    moduleList = [...moduleList, ...module];\n  });\n  console.log(\n    chalk.green(\n      \"---------------------------------------------------------------\"\n    )\n  );\n  console.log(chalk.green(\"导出成功！\"));\n  return moduleList;\n};\n\n// 参数item类型\nconst interfaceParamsList = (params) => {\n  let str = \"\";\n  params.forEach((item) => {\n    str = `${str}\n      /** ${item.description ? item.description : \"\"} **/\n      ${item.name}${item.required ? \"?\" : \"\"}: ${dataType(item.type)}; \n    `;\n  });\n  return str;\n};\n\n// 定义参数类型\nconst interfaceParamsTpl = (params, interfaceName) => {\n  if (!params || params.length === 0) {\n    return \"\";\n  } else {\n    return `interface ${interfaceName} {\n      ${interfaceParamsList(params)}\n    }`;\n  }\n};\n\n// 设置单个接口写入模板\nconst tplInsertApi = (apiInfo) => {\n  const keys = Object.keys(apiInfo);\n  const method = keys[0];\n  const methodParams = apiInfo[method];\n  const parameters = methodParams.parameters; // 接口参数\n  const operationId = methodParams.operationId;\n  const allPath = apiInfo.allPath; // 接口地址\n  const summary = methodParams.summary; // 接口描述\n  const requestName = moduleName(operationId); // 接口名称格式化\n\n  let interfaceName = \"any\"; // 定义接口name\n  let interfaceParams = \"data?:any\"; // 定义参数及类型\n  let parametersType = \"data\"; // 请求类型\n\n  if (parameters && parameters.length > 0) {\n    interfaceName = `${requestName}Ife`;\n    interfaceParams = `data?: ${interfaceName}`;\n  }\n  // get请求默认为json传参\n  if (method.toLocaleLowerCase() === \"get\") {\n    parametersType = \"params\";\n    interfaceParams = `params?: ${interfaceName}`;\n  }\n\n  return apiConfig(\n    summary,\n    interfaceParamsTpl(parameters, interfaceName),\n    requestName,\n    interfaceParams,\n    method,\n    allPath,\n    parametersType\n  );\n};\n\n// 接口名称（使用operationId）\nconst getModulesName = (apiInfo) => {\n  const keys = Object.keys(apiInfo);\n  const method = keys[0];\n  const methodParams = apiInfo[method];\n  const operationId = methodParams.operationId;\n  return operationId;\n};\n\n// 单个文件顶部配置\nconst setTopConfig = () => {\n  let config = topConfig;\n  return config;\n};\n\n// 写入文件\nconst writeFileApi = (fileName, apiData) => {\n  // 设置文件顶部配置（如引入axios/定义响应类型等）\n  let tplIndex = setTopConfig();\n  const apiDataLen = apiData.length;\n  let moduleList = [];\n  for (let i = 0; i < apiDataLen; i++) {\n    const item = apiData[i];\n    tplIndex = `${tplIndex}\\n${tplInsertApi(item)}\\n`;\n    moduleList.push(getModulesName(item));\n  }\n  tplIndex = beautify(tplIndex, {\n    indent_size: 2, // 缩进宽度，默认为4\n    max_preserve_newlines: 2, // 保留的最大换行符数量，默认为10\n    space_in_paren: true, // 圆括号内是否保留空格，默认为false\n    preserve_newlines: false, // 是否保留换行符，默认为true\n    // jslint_happy: true, // 是否启用JSLint风格，默认为false\n  });\n  fs.writeFileSync(`${API_PATH}/${fileName}.ts`, tplIndex);\n  console.log(\n    chalk.blue(\n      `${fileName}.ts` +\n        chalk.green(\" ------------ \") +\n        chalk.black(\"[\" + apiDataLen + \"]\") +\n        chalk.green(\"个接口写入完成\")\n    )\n  );\n  return moduleList;\n};\n\nconst gen = async () => {\n  rmDir(API_PATH);\n  isExist();\n  try {\n    let parsed;\n    if (demo) {\n      parsed = demoData;\n    } else {\n      // 解析url 获得\n      parsed = await parse.parse(swaggerUrl);\n    }\n\n    const paths = parsed.paths;\n    const pathsKeys = Object.keys(paths);\n    const pathsKeysLen = pathsKeys.length;\n    console.log(\n      chalk.blue(\"开始解析，总共接口数量：\") + chalk.yellow(pathsKeysLen)\n    );\n    console.log(\n      chalk.red(\n        \"---------------------------------------------------------------\"\n      )\n    );\n\n    const modulesMap = new Map();\n    for (let i = 0; i < pathsKeysLen; i++) {\n      const item = pathsKeys[i];\n      const itemAry = item.split(\"/\");\n      const pathsItem = paths[item];\n      let fileName = itemAry[dirIdx || 2];\n      if (!fileName) continue;\n      fileName = fileName.toLowerCase();\n      pathsItem.allPath = item;\n      if (modulesMap.has(fileName)) {\n        // 继续添加到当前 fileName 文件内\n        const fileNameAry = modulesMap.get(fileName);\n        fileNameAry.push(pathsItem);\n        modulesMap.set(fileName, fileNameAry);\n      } else {\n        modulesMap.set(fileName, [pathsItem]);\n      }\n    }\n    // 获取模块，并写入文件\n    getModules(modulesMap);\n  } catch (e) {\n    console.log(e);\n  }\n};\n\nmodule.exports = {\n  gen,\n};\n\n```\n## 其他\n初次提交，在本公司项目中，使用是完全支持了，但是不可避免，可能存在问题，如有发现，欢迎提出，感谢！（后期有时间的话，打算搞成vscode插件）\n",
    "tag": "工作总结,javascript,Typescript,插件封装",
    "apply": "否",
    "original": "是",
    "comment": "1",
    "description": "当前公司开发，后端通过swagger提供接口文档，开发某些模块时，一下子可能生成二三十个接口，前端使用的时候，需要一个一个copy到对应的api文件中，定义类型，引入接口等等，实在是麻烦！于是花了点时间，搞了下自动导出",
